// /* eslint-disable @typescript-eslint/quotes */
/* eslint-disable comma-dangle */
import { resolve } from 'path';
import vue from '@vitejs/plugin-vue';
// import progress from 'vite-plugin-progress';
import svgLoader from 'vite-svg-loader';
import vueJsx from '@vitejs/plugin-vue-jsx';

import AutoImport from 'unplugin-auto-import/vite';
import Components from 'unplugin-vue-components/vite';
import { AntDesignVueResolver } from 'unplugin-vue-components/resolvers';
import type { UserConfigExport, ConfigEnv } from 'vite';
import { defineConfig, loadEnv } from 'vite';
import removeKeywordPlugin, { getArgs } from './vite-plugin-remove-and-hide';
import removeConsole from 'vite-plugin-remove-console';
import postcssImport from 'postcss-import';
import autoprefixer from 'autoprefixer';
import tailwindcss from 'tailwindcss';

const isDevelopment = process.env.NODE_ENV === 'development';
const baseSrc = resolve(__dirname, './src');

const config = ({ mode }: ConfigEnv): UserConfigExport => {
  const root = process.cwd();
  const env = loadEnv(mode, `${root}/env`);
  console.log({ env });
  const { removeKeys } = getArgs() || {};
  const plugins = [
    vue(),
    // jsx、tsx语法支持
    vueJsx(),
    // svg组件化支持
    svgLoader(),
    AutoImport({
      imports: [
        'vue',
        'vue-router',
        'vue-i18n',
        '@vueuse/core',
        'pinia',
      ],
      dts: 'types/auto-imports.d.ts',
      dirs: ['src/store', 'src/composables'],
    }),
    Components({
      // 指定组件位置，默认是src/components
      dirs: ['src/components'],
      extensions: ['vue'],
      // 配置文件生成位置
      dts: 'types/components.d.ts',
      // ui库解析器
      resolvers: [AntDesignVueResolver({
        importStyle: false
      })],
    }),
    // 生产环境下删除console.log
    !isDevelopment ? removeConsole() : null,
  ];
  if (removeKeys) {
    console.log('移除星海关键字等logo打包.....');
    plugins.push(removeKeywordPlugin({
      keywords: [
        '星海 ·', '星海·', '星海', '电信', '中国电信', 'AI公司', '电信', '电信AI',
        '中电信人工智能科技(北京)有限公司', '91110102MAD55U9H0F',
        '人工智能公司', '人工智能科技公司', '天翼AI',
        '星辰', '星河',
      ], // 移除关键字
      hideClasses: ['logoImgHide'] // 隐藏元素
    }));
  }


  return defineConfig({
    envDir: resolve(__dirname, './env'),
    base: env.VITE_BASE_PATH,
    plugins,
    resolve: {
      alias: [
        {
          find: 'lodash',
          replacement: 'lodash-es',
        },
        {
          find: '~@',
          replacement: baseSrc,
        },
        {
          find: '~',
          replacement: baseSrc,
        },
        {
          find: '@',
          replacement: baseSrc,
        },
        {
          find: '~#',
          replacement: resolve(baseSrc, './enums'),
        },
      ]
    },
    css: {
      postcss: {
        plugins: [
          postcssImport,
          autoprefixer,
          tailwindcss,
          {
            postcssPlugin: 'internal:charset-removal',
            AtRule: {
              charset: (atRule) => {
                if (atRule.name === 'charset') {
                  atRule.remove();
                }
              }
            }
          }
        ]
      },
      preprocessorOptions: {
        scss: {
          // eslint-disable-next-line quotes
          additionalData: `@use '@/styles/theme/theme.scss' as *;`,
        }
      }
    },
    // 服务端渲染
    server: {
      hmr: true,
      host: '0.0.0.0',
      port: 3003,
      cors: true,

      // 设置开发环境proxy代理
      proxy: {
        '/tap-api': {
          target: 'http://10.127.188.221:6081/',
          // target: 'http://10.127.183.194:9090/',// 徐文涛
          // target:'http://10.127.183.28:9090/',// 朱彤彤
          // target:'http://10.127.183.197:9090/',// 宋鹏飞
          // target:'http://10.127.183.151:9090/',// 付一健
          // target: 'http://10.127.162.136:18999/',
          changeOrigin: true,
          // rewrite: path => path.replace(/^\/tap-api/, ''),
          ws: true
        },
        '/tbk-api': {
          target: 'http://10.127.183.138:19991/', // 法虎
          changeOrigin: true,
          rewrite: path => path.replace(/^\/tbk-api/, ''),
          ws: true
        },
      },
      watch: {
        // 忽略对 'auto-import.d.ts' 文件的更改
        ignored: ['**/auto-import.d.ts']
      }
    },
    build: {
      target: 'es2019',
      outDir: 'dist',
      // 启用/禁用 brotli 压缩大小报告。压缩大型输出文件可能会很慢，因此禁用该功能可能会提高大型项目的构建性能。
      chunkSizeWarningLimit: 2000,
      // 配置静态资源路径
      assetsDir: 'static/assets',
      rollupOptions: {
        output: {
          chunkFileNames: 'static/js/[name]-[hash].js',
          entryFileNames: 'static/js/[name]-[hash].js',
          assetFileNames: 'static/assets/[name]-[hash].[ext]',
        }
      }
    }
  });
};

export default config;
